namespace sv_36d34d870ed5494e8cc4afabb84f6d30.Services;

public class WarehouseState
{
    public string SelectedWarehouseId { get; private set; } = "WH-001";
    public string SelectedWarehouseName { get; private set; } = "Warehouse A";

    public event Action? OnChange;

    public static readonly (string Id, string Name)[] AvailableWarehouses =
    [
        ("WH-001", "Warehouse A"),
        ("WH-002", "Warehouse B"),
        ("WH-003", "Warehouse C"),
    ];

    public void SetWarehouse(string warehouseId)
    {
        var warehouse = AvailableWarehouses.FirstOrDefault(w => w.Id == warehouseId);
        if (warehouse == default || warehouse.Id == SelectedWarehouseId)
            return;

        SelectedWarehouseId = warehouse.Id;
        SelectedWarehouseName = warehouse.Name;
        OnChange?.Invoke();
    }
}

namespace sv_36d34d870ed5494e8cc4afabb84f6d30.Services;

/// <summary>
/// Scoped service that tracks low-stock alert counts for a warehouse.
/// Fires OnAlertCountChanged whenever new data arrives so all subscribed
/// components can update — not just the one that triggered the poll.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _activePollRequests;

    public int CurrentAlertCount { get; private set; }

    /// <summary>
    /// Components subscribe to this event to re-render when alert data changes.
    /// Always wrap the handler in InvokeAsync(StateHasChanged) because the
    /// event fires from a background timer thread.
    /// </summary>
    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += OnWarehouseChanged;
    }

    /// <summary>Simulates a database query returning 0–15 low-stock items.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Call when a page that displays alerts becomes visible.
    /// Multiple components can call this; polling starts on the first call
    /// and stops when all components call StopPolling.
    /// </summary>
    public void StartPolling()
    {
        _activePollRequests++;
        if (_activePollRequests == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollLoopAsync(_cts.Token);
        }
    }

    /// <summary>
    /// Call when the page that requested polling is disposed.
    /// </summary>
    public void StopPolling()
    {
        _activePollRequests = Math.Max(0, _activePollRequests - 1);
        if (_activePollRequests == 0)
        {
            CancelTimer();
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fetch immediately on start, then every 10 seconds.
        await FetchAndNotifyAsync();

        while (_timer is not null && !ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer.WaitForNextTickAsync(ct))
                    break;
            }
            catch (OperationCanceledException)
            {
                break;
            }

            await FetchAndNotifyAsync();
        }
    }

    private async Task FetchAndNotifyAsync()
    {
        CurrentAlertCount = await GetLowStockCountAsync(_warehouseState.SelectedWarehouseId);
        OnAlertCountChanged?.Invoke();
    }

    private void OnWarehouseChanged()
    {
        // When the warehouse changes, fetch fresh data immediately
        // so every subscriber sees the updated count.
        _ = FetchAndNotifyAsync();
    }

    private void CancelTimer()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= OnWarehouseChanged;
        CancelTimer();
    }
}

