arguments.file_text:
@page "/dashboard"
@rendermode InteractiveServer
@inject sv_36d34d870ed5494e8cc4afabb84f6d30.Services.WarehouseState WarehouseState
@inject sv_36d34d870ed5494e8cc4afabb84f6d30.Services.InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard - @WarehouseState.SelectedWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Site</h5>
        <p class="card-text fs-4">
            <strong>@WarehouseState.SelectedWarehouseName</strong>
            <span class="text-muted">(@WarehouseState.SelectedWarehouseId)</span>
        </p>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text">
            @if (AlertService.CurrentAlertCount > 0)
            {
                <span class="fs-2 text-danger fw-bold">@AlertService.CurrentAlertCount</span>
                <span class="text-muted ms-2">items below minimum levels</span>
            }
            else
            {
                <span class="fs-2 text-success fw-bold">0</span>
                <span class="text-muted ms-2">all stock levels healthy</span>
            }
        </p>
        <p class="text-muted"><small>Refreshes every 10 seconds</small></p>
    </div>
</div>

@code {
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        _alertHandler = () => InvokeAsync(StateHasChanged);

        WarehouseState.OnChange += _warehouseHandler;
        AlertService.OnAlertCountChanged += _alertHandler;

        // Start polling when the dashboard is visible.
        AlertService.StartPolling();
    }

    public void Dispose()
    {
        // Stop polling when the user leaves the page.
        AlertService.StopPolling();
        WarehouseState.OnChange -= _warehouseHandler;
        AlertService.OnAlertCountChanged -= _alertHandler;
    }
}

